using System.ComponentModel.DataAnnotations;

namespace RecipeShare.Models;

public class Recipe
{
    public int Id { get; set; }

    [Required, StringLength(100)]
    public string Title { get; set; } = string.Empty;

    [Required]
    public string Category { get; set; } = string.Empty;

    [Required]
    public string Ingredients { get; set; } = string.Empty;

    [Required]
    public string Steps { get; set; } = string.Empty;

    public List<int> Ratings { get; set; } = [];

    public double AverageRating => Ratings.Count > 0
        ? Math.Round(Ratings.Average(), 1)
        : 0;
}

using RecipeShare.Models;

namespace RecipeShare.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes =
    [
        new()
        {
            Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
            Ingredients = "Pizza dough, San Marzano tomatoes, Fresh mozzarella, Fresh basil, Olive oil, Salt",
            Steps = "1. Preheat oven to 475°F.\n2. Roll out dough on a floured surface.\n3. Spread crushed tomatoes evenly.\n4. Tear mozzarella and distribute over sauce.\n5. Bake 10-12 minutes until crust is golden.\n6. Top with fresh basil and a drizzle of olive oil.",
            Ratings = [5, 4, 5, 4, 5]
        },
        new()
        {
            Id = 2, Title = "Spaghetti Carbonara", Category = "Italian",
            Ingredients = "Spaghetti, Guanciale, Eggs, Pecorino Romano, Black pepper",
            Steps = "1. Cook spaghetti in salted boiling water.\n2. Crisp guanciale in a pan.\n3. Whisk eggs with grated Pecorino and pepper.\n4. Toss hot pasta with guanciale.\n5. Remove from heat and stir in egg mixture.\n6. Serve immediately with extra Pecorino.",
            Ratings = [5, 5, 4]
        },
        new()
        {
            Id = 3, Title = "Chicken Tikka Masala", Category = "Indian",
            Ingredients = "Chicken thighs, Yogurt, Garam masala, Cumin, Tomato sauce, Heavy cream, Garlic, Ginger, Onion",
            Steps = "1. Marinate chicken in yogurt and spices for 2 hours.\n2. Grill or broil chicken until charred.\n3. Sauté onion, garlic, and ginger.\n4. Add tomato sauce, garam masala, and cumin.\n5. Simmer 15 minutes, then add cream.\n6. Add chicken pieces and simmer 10 more minutes.",
            Ratings = [5, 4, 4, 5]
        },
        new()
        {
            Id = 4, Title = "Vegetable Pad Thai", Category = "Thai",
            Ingredients = "Rice noodles, Tofu, Bean sprouts, Peanuts, Lime, Tamarind paste, Fish sauce, Sugar, Garlic, Eggs",
            Steps = "1. Soak rice noodles in warm water 20 minutes.\n2. Mix tamarind paste, fish sauce, and sugar for sauce.\n3. Stir-fry tofu until golden, set aside.\n4. Scramble eggs in the wok.\n5. Add noodles and sauce, toss until coated.\n6. Top with bean sprouts, peanuts, and lime.",
            Ratings = [4, 4, 5]
        },
        new()
        {
            Id = 5, Title = "Beef Tacos", Category = "Mexican",
            Ingredients = "Ground beef, Taco shells, Lettuce, Tomato, Cheddar cheese, Sour cream, Cumin, Chili powder, Garlic",
            Steps = "1. Brown ground beef with garlic, cumin, and chili powder.\n2. Warm taco shells in the oven.\n3. Dice tomato and shred lettuce.\n4. Fill shells with seasoned beef.\n5. Top with cheese, lettuce, tomato, and sour cream.",
            Ratings = [4, 5, 4, 4]
        },
        new()
        {
            Id = 6, Title = "Guacamole", Category = "Mexican",
            Ingredients = "Avocados, Lime juice, Red onion, Cilantro, Jalapeño, Salt, Tomato",
            Steps = "1. Halve and pit avocados, scoop into bowl.\n2. Mash to desired consistency.\n3. Stir in diced onion, tomato, and jalapeño.\n4. Add lime juice, cilantro, and salt.\n5. Serve immediately with tortilla chips.",
            Ratings = [5, 5, 5]
        },
        new()
        {
            Id = 7, Title = "Green Curry", Category = "Thai",
            Ingredients = "Green curry paste, Coconut milk, Chicken breast, Thai basil, Bamboo shoots, Fish sauce, Sugar, Thai eggplant",
            Steps = "1. Heat coconut cream in a wok until oil separates.\n2. Fry curry paste until fragrant.\n3. Add sliced chicken and cook through.\n4. Pour in remaining coconut milk.\n5. Add bamboo shoots and eggplant, simmer 10 minutes.\n6. Season with fish sauce and sugar, garnish with Thai basil.",
            Ratings = [4, 5]
        },
        new()
        {
            Id = 8, Title = "Dal Makhani", Category = "Indian",
            Ingredients = "Black lentils, Kidney beans, Butter, Cream, Tomato puree, Garlic, Ginger, Garam masala, Cumin",
            Steps = "1. Soak lentils and kidney beans overnight.\n2. Pressure cook until tender.\n3. Sauté garlic and ginger in butter.\n4. Add tomato puree and spices, cook 5 minutes.\n5. Combine with lentils and simmer on low heat 30 minutes.\n6. Stir in cream and finish with a knob of butter.",
            Ratings = [5, 4, 5, 5]
        }
    ];

    private int _nextId = 9;

    public IReadOnlyList<string> GetCategories() =>
        _recipes.Select(r => r.Category).Distinct().Order().ToList();

    public IReadOnlyList<Recipe> GetByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetById(int id) =>
        _recipes.FirstOrDefault(r => r.Id == id);

    public void Add(Recipe recipe)
    {
        recipe.Id = _nextId++;
        _recipes.Add(recipe);
    }

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is not null && stars is >= 1 and <= 5)
        {
            recipe.Ratings.Add(stars);
        }
    }
}

