@page "/"
@inject RecipeShare.Services.RecipeService RecipeService

<PageTitle>RecipeShare — Home</PageTitle>

<h1>🍽️ Welcome to RecipeShare</h1>
<p class="lead">Discover and share delicious recipes from around the world.</p>

<h2 class="mt-4">Browse by Category</h2>
<div class="row mt-3">
    @foreach (var category in RecipeService.GetCategories())
    {
        <div class="col-md-4 mb-3">
            <div class="card h-100">
                <div class="card-body d-flex flex-column">
                    <h5 class="card-title">@CategoryEmoji(category) @category</h5>
                    <p class="card-text text-muted">
                        @RecipeService.GetByCategory(category).Count recipe(s)
                    </p>
                    <a href="category/@category" class="btn btn-primary mt-auto">Browse</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private static string CategoryEmoji(string category) => category switch
    {
        "Italian" => "🇮🇹",
        "Indian" => "🇮🇳",
        "Thai" => "🇹🇭",
        "Mexican" => "🇲🇽",
        _ => "🍴"
    };
}

