@page "/category/{CategoryName}"
@inject RecipeShare.Services.RecipeService RecipeService

<PageTitle>@CategoryName Recipes — RecipeShare</PageTitle>

<h1>@CategoryName Recipes</h1>

@if (recipes.Count == 0)
{
    <div class="alert alert-info mt-3">No recipes found in this category.</div>
}
else
{
    <div class="row mt-3">
        @foreach (var recipe in recipes)
        {
            <div class="col-md-6 mb-3">
                <div class="card h-100">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="card-text">
                            <span class="text-warning">@RenderStars(recipe.AverageRating)</span>
                            <small class="text-muted ms-1">(@recipe.Ratings.Count ratings)</small>
                        </p>
                        <a href="recipe/@recipe.Id" class="btn btn-outline-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

<a href="/" class="btn btn-link mt-2">← Back to categories</a>

@code {
    [Parameter] public string CategoryName { get; set; } = string.Empty;

    private IReadOnlyList<RecipeShare.Models.Recipe> recipes = [];

    protected override void OnParametersSet()
    {
        recipes = RecipeService.GetByCategory(CategoryName);
    }

    private static string RenderStars(double rating)
    {
        int full = (int)Math.Floor(rating);
        int empty = 5 - full;
        return new string('★', full) + new string('☆', empty);
    }
}

@page "/recipe/{Id:int}"
@inject RecipeShare.Services.RecipeService RecipeService

<PageTitle>@(recipe?.Title ?? "Recipe") — RecipeShare</PageTitle>

@if (recipe is null)
{
    <div class="alert alert-warning">Recipe not found.</div>
    <a href="/" class="btn btn-link">← Back to home</a>
}
else
{
    <h1>@recipe.Title</h1>
    <span class="badge bg-secondary mb-3">@recipe.Category</span>

    <div class="row mt-3">
        <div class="col-md-6">
            <div class="card mb-3">
                <div class="card-header"><strong>Ingredients</strong></div>
                <ul class="list-group list-group-flush">
                    @foreach (var ingredient in recipe.Ingredients.Split(',', StringSplitOptions.TrimEntries))
                    {
                        <li class="list-group-item">@ingredient</li>
                    }
                </ul>
            </div>
        </div>
        <div class="col-md-6">
            <div class="card mb-3">
                <div class="card-header"><strong>Steps</strong></div>
                <div class="card-body">
                    @foreach (var step in recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
                    {
                        <p>@step</p>
                    }
                </div>
            </div>
        </div>
    </div>

    <div class="card mt-3">
        <div class="card-body">
            <h5>Rate this recipe</h5>
            <p class="text-muted mb-2">
                Average: @recipe.AverageRating / 5
                <small>(@recipe.Ratings.Count ratings)</small>
            </p>
            <RecipeShare.Components.StarRating RecipeId="recipe.Id" />
        </div>
    </div>

    <a href="category/@recipe.Category" class="btn btn-link mt-3">← Back to @recipe.Category recipes</a>
}

@code {
    [Parameter] public int Id { get; set; }

    private RecipeShare.Models.Recipe? recipe;

    protected override void OnParametersSet()
    {
        recipe = RecipeService.GetById(Id);
    }
}

@rendermode InteractiveServer
@inject RecipeShare.Services.RecipeService RecipeService

<div class="star-rating">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= selectedRating ? "selected" : "")"
              role="button"
              @onclick="() => Rate(star)"
              title="@star star(s)">
            @(star <= selectedRating ? "★" : "☆")
        </span>
    }
    @if (submitted)
    {
        <span class="text-success ms-2">Thanks for rating!</span>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public int RecipeId { get; set; }

    private int selectedRating;
    private bool submitted;

    private void Rate(int stars)
    {
        selectedRating = stars;
        RecipeService.AddRating(RecipeId, stars);
        submitted = true;
    }
}

.star-rating .star {
    font-size: 1.8rem;
    cursor: pointer;
    color: #ccc;
    transition: color 0.15s;
}

.star-rating .star:hover,
.star-rating .star.selected {
    color: #f5a623;
}

