@page "/recipe/{Id:int}"
@inject RecipeShare.Services.RecipeService RecipeService

<PageTitle>@(recipe?.Title ?? "Recipe") — RecipeShare</PageTitle>

@if (recipe is null)
{
    <div class="alert alert-warning">Recipe not found.</div>
    <a href="/" class="btn btn-link">← Back to home</a>
}
else
{
    <h1>@recipe.Title</h1>
    <span class="badge bg-secondary mb-3">@recipe.Category</span>

    <div class="row mt-3">
        <div class="col-md-6">
            <div class="card mb-3">
                <div class="card-header"><strong>Ingredients</strong></div>
                <ul class="list-group list-group-flush">
                    @foreach (var ingredient in recipe.Ingredients.Split(',', StringSplitOptions.TrimEntries))
                    {
                        <li class="list-group-item">@ingredient</li>
                    }
                </ul>
            </div>
        </div>
        <div class="col-md-6">
            <div class="card mb-3">
                <div class="card-header"><strong>Steps</strong></div>
                <div class="card-body">
                    @foreach (var step in recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
                    {
                        <p>@step</p>
                    }
                </div>
            </div>
        </div>
    </div>

    <div class="card mt-3">
        <div class="card-body">
            <h5>Rate this recipe</h5>
            <p class="text-muted mb-2">
                Average: @recipe.AverageRating / 5
                <small>(@recipe.Ratings.Count ratings)</small>
            </p>
            <RecipeShare.Components.StarRating RecipeId="recipe.Id" />
        </div>
    </div>

    <a href="category/@recipe.Category" class="btn btn-link mt-3">← Back to @recipe.Category recipes</a>
}

@code {
    [Parameter] public int Id { get; set; }

    private RecipeShare.Models.Recipe? recipe;

    protected override void OnParametersSet()
    {
        recipe = RecipeService.GetById(Id);
    }
}

