@rendermode InteractiveServer
@inject RecipeShare.Services.RecipeService RecipeService

<div class="star-rating">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= selectedRating ? "selected" : "")"
              role="button"
              @onclick="() => Rate(star)"
              title="@star star(s)">
            @(star <= selectedRating ? "★" : "☆")
        </span>
    }
    @if (submitted)
    {
        <span class="text-success ms-2">Thanks for rating!</span>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public int RecipeId { get; set; }

    private int selectedRating;
    private bool submitted;

    private void Rate(int stars)
    {
        selectedRating = stars;
        RecipeService.AddRating(RecipeId, stars);
        submitted = true;
    }
}

