@page "/submit"
@rendermode InteractiveServer
@inject RecipeShare.Services.RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe — RecipeShare</PageTitle>

<h1>📝 Submit a Recipe</h1>

<div class="row">
    <div class="col-md-8">
        <EditForm Model="Recipe" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
            <DataAnnotationsValidator />
            <ValidationSummary />

            <div class="mb-3">
                <label class="form-label">Title</label>
                <InputText @bind-Value="Recipe!.Title" class="form-control" placeholder="e.g. Grandma's Apple Pie" />
                <ValidationMessage For="() => Recipe!.Title" />
            </div>

            <div class="mb-3">
                <label class="form-label">Category</label>
                <InputSelect @bind-Value="Recipe!.Category" class="form-select">
                    <option value="">-- Select a category --</option>
                    @foreach (var cat in categories)
                    {
                        <option value="@cat">@cat</option>
                    }
                    <option value="Other">Other</option>
                </InputSelect>
                <ValidationMessage For="() => Recipe!.Category" />
            </div>

            <div class="mb-3">
                <label class="form-label">Ingredients</label>
                <InputTextArea @bind-Value="Recipe!.Ingredients" class="form-control" rows="4"
                    placeholder="Comma-separated: Flour, Sugar, Butter, Apples..." />
                <ValidationMessage For="() => Recipe!.Ingredients" />
            </div>

            <div class="mb-3">
                <label class="form-label">Steps</label>
                <InputTextArea @bind-Value="Recipe!.Steps" class="form-control" rows="6"
                    placeholder="1. Preheat oven to 350°F.&#10;2. Mix dry ingredients.&#10;3. ..." />
                <ValidationMessage For="() => Recipe!.Steps" />
            </div>

            <button type="submit" class="btn btn-success" disabled="@isSubmitting">
                @(isSubmitting ? "Submitting..." : "Submit Recipe")
            </button>
        </EditForm>
    </div>
</div>

@code {
    [SupplyParameterFromForm]
    private RecipeShare.Models.Recipe? Recipe { get; set; }

    private IReadOnlyList<string> categories = [];
    private bool isSubmitting;

    protected override void OnInitialized()
    {
        Recipe ??= new();
        categories = RecipeService.GetCategories();
    }

    private void HandleSubmit()
    {
        isSubmitting = true;
        RecipeService.Add(Recipe!);
        Navigation.NavigateTo($"/recipe/{Recipe!.Id}");
    }
}

